def render_trend_chart(pivoted_df, title, brands_order=None, is_percentage=True):
    """Render a Plotly line chart from a pivoted DataFrame (quarters x brands)."""
    if pivoted_df.empty:
        st.info(f"No data available for: {title}")
        return

    import plotly.io as pio
    pio.templates.default = "plotly_white"

    fig = go.Figure()
    brands = brands_order if brands_order else list(pivoted_df.columns)

    for i, brand in enumerate(brands):
        if brand in pivoted_df.columns:
            y_vals = pivoted_df[brand].tolist()
            if i == 0:
                # Primary brand - show data labels
                text_vals = [f"{v:.2f}" if pd.notna(v) else "" for v in y_vals] if is_percentage else [f"{v:,.0f}" if pd.notna(v) else "" for v in y_vals]
                hover_fmt = f"<b>{brand}</b><br>%{{x}}<br>%{{y:.2f}}%<extra></extra>" if is_percentage else f"<b>{brand}</b><br>%{{x}}<br>%{{y:,.0f}}<extra></extra>"
                fig.add_trace(go.Scatter(
                    x=pivoted_df.index.tolist(),
                    y=y_vals,
                    mode="lines+markers+text",
                    name=brand,
                    text=text_vals,
                    textposition="top center",
                    textfont=dict(size=10, color="#0093D0"),
                    line=dict(color=CHART_COLORS[0], width=3),
                    marker=dict(size=7),
                    hovertemplate=hover_fmt
                ))
            else:
                # Competitor brands - no data labels
                hover_fmt = f"<b>{brand}</b><br>%{{x}}<br>%{{y:.2f}}%<extra></extra>" if is_percentage else f"<b>{brand}</b><br>%{{x}}<br>%{{y:,.0f}}<extra></extra>"
                fig.add_trace(go.Scatter(
                    x=pivoted_df.index.tolist(),
                    y=y_vals,
                    mode="lines+markers",
                    name=brand,
                    line=dict(color=CHART_COLORS[i % len(CHART_COLORS)], width=2),
                    marker=dict(size=5),
                    hovertemplate=hover_fmt
                ))

    fig.update_layout(
        template="plotly_white",
        height=420,
        margin=dict(l=60, r=30, t=20, b=50),
        plot_bgcolor="#FFFFFF",
        paper_bgcolor="#FFFFFF",
        font=dict(family="Noto Sans, sans-serif", size=13, color="#1A1A1A"),
        legend=dict(orientation="h", yanchor="bottom", y=1.02, xanchor="left", x=0, font=dict(size=12, color="#616365")),
        hovermode="x unified"
    )
    fig.update_xaxes(
        showgrid=False,
        tickfont=dict(size=12, color="#616365"),
        linecolor="#E6E9EC",
        tickcolor="#E6E9EC",
        ticks="outside",
        title_text=""
    )
    fig.update_yaxes(
        showgrid=True,
        gridcolor="#E6E9EC",
        ticksuffix="%" if is_percentage else "",
        tickfont=dict(size=12, color="#616365"),
        linecolor="#E6E9EC",
        tickcolor="#E6E9EC",
        ticks="outside",
        title_text="",
        separatethousands=True
    )
    # Use theme=None to prevent Streamlit from overriding Plotly colors
    try:
        st.plotly_chart(fig, use_container_width=True, theme=None)
    except TypeError:
        # Older Streamlit versions don't support theme parameter
        st.plotly_chart(fig, use_container_width=True)


